-- Idempotent: PDF metin icerigi + partner/firma PDF kayitlari
SET NOCOUNT ON; SET XACT_ABORT ON; SET QUOTED_IDENTIFIER ON; SET ANSI_NULLS ON;

DECLARE @kullanici_kullanim_kosullari_html nvarchar(max) = N'<h2>OTELTURİZM.COM</h2><h2>KULLANICI (MÜŞTERI) KULLANIM VE REZERVASYON SÖZLEŞMESI</h2><p>İşbu Sözleşme,  otelturizm.com (bundan böyle &quot;Platform&quot; olarak anılacaktır) hizmetlerini kullanarak konaklama rezervasyonu  yapan  Kullanıcılar  (Müşteri)  ile  Platform  arasındaki  hukuki  çerçeveyi,  tarafların  hak  ve yükümlülüklerini belirler.</p><h2>1. PLATFORMUN ARACI ROLÜ</h2><p>Platform, 6563 sayılı Elektronik Ticaretin Düzenlenmesi Hakkında Kanun uyarınca bir &quot;Aracı Hizmet Sağlayıcı&quot;dır. Platform, bünyesinde listelenen konaklama tesislerinin (Otellerin) maliki, işletmecisi veya tur operatörü değildir. Konaklama sözleşmesi, doğrudan rezervasyon yapılan Tesis ile Müşteri arasında kurulmaktadır.</p><h2>2. KULLANICI HAKLARININ KORUNMASI VE HAK TALEBİ</h2><p>A. Tesis Kaynaklı Overbooking (Aşırı Rezervasyon) Durumu Otelin kontenjanlarını yanlış bildirmesi nedeniyle tesise ulaştığınızda odanızın hazır olmaması (overbooking) durumunda tüm yasal sorumluluk ilgili Otele aittir. Müşteri bu durumda; Otelden, aynı bölgede ve eşdeğer (veya daha üst) standartta bir tesise ücretsiz transfer edilmesini ve konaklatılmasını talep etme hakkına sahiptir. Sürecin çözülememesi halinde, ödenen tüm ücretlerin iadesini ve uğranılan zararların doğrudan Otelden tazminini talep etme hakkı saklıdır. Platform, Tüketici haklarının korunması için Otel nezdinde gerekli yaptırımları uygular. B. Ayıplı Hizmet İddiası ve Müşteri Şikayetleri Platformda  ilan  edilen  fotoğraflar,  konsept  bilgileri  (havuz,  klima,  temizlik  vb.)  ile  Tesisin  fiili  durumu uyuşmuyorsa, Tüketici 6502 sayılı Kanun kapsamında  &quot;Ayıplı Hizmet&quot; ihbarında bulunabilir. Şikayetinizi, tesise giriş yaptıktan hemen sonra hem Otel yönetimine hem de otelturizm.com Müşteri Hizmetlerine yazılı (e- posta/uygulama üzerinden) bildirmeniz gerekmektedir.</p><h2>3. İPTAL, İADE VE REZERVASYON DEĞİŞİKLİĞİ</h2><p>İptal şartları, seçmiş olduğunuz Otel ve Oda tipine göre (İptal Edilebilir / İptal Edilemez fiyat politikaları) değişiklik gösterir. İptal süresi geçtikten sonra yapılan veya &quot;İptal Edilemez&quot; ibareli rezervasyonlarda iade yapılmaması yasal mevzuata uygundur. Ancak, mücbir sebep (tam teşekküllü devlet hastanesinden alınmış hastalık raporu, ölüm, doğal afet) sunulması halinde, Platform Tüketici lehine Otel ile müzakere sürecini yürütür.</p><h2>4. GÜVENLİ ÖDEME VE KİŞİSEL VERİLER</h2><p>Platform  üzerinden  gerçekleştirilen  tüm  kredi  kartı/banka  kartı  ödemeleri  3D  Secure  altyapısı  ile  PCI-DSS standartlarına uygun olarak gerçekleştirilir. Kart bilgileriniz Platform sunucularında saklanmaz. Hizmetin doğası gereği kimlik ve iletişim bilgileriniz sadece konaklama hizmetinin ifası için ilgili Otel ile paylaşılır. Kullanıcı, rezervasyon butonuna tıklamakla ve ödeme işlemini gerçekleştirmekle işbu sözleşmenin tüm maddelerini okumuş, anlamış ve elektronik ortamda gayrikabili rücu olarak onaylamış kabul edilir.</p>';
DECLARE @kullanici_kullanim_kosullari_ozet nvarchar(max) = N'<p>İşbu Sözleşme,  otelturizm.com (bundan böyle &amp;quot;Platform&amp;quot; olarak anılacaktır) hizmetlerini kullanarak konaklama rezervasyonu  yapan  Kullanıcılar  (Müşteri)  ile  Platform  arasındaki  hukuki  çerçeveyi,  tarafların  hak  ve yükümlülüklerini belirler.</p>';
UPDATE [dbo].[SOZLESMELER] SET [ICERIK_HTML]=@kullanici_kullanim_kosullari_html, [OZET_HTML]=@kullanici_kullanim_kosullari_ozet, [VERSIYON_NO]=CASE WHEN [VERSIYON_NO]<2 THEN 2 ELSE [VERSIYON_NO] END, [GUNCELLENME_TARIHI]=SYSUTCDATETIME() WHERE [SLUG]=N'kullanici-kullanim-kosullari' AND [AKTIF_MI]=1;

DECLARE @kullanici_kvkk_aydinlatma_html nvarchar(max) = N'<h2>OTELTURİZM.COM</h2><h2>KIŞISEL VERILERIN KORUNMASI (KVKK) AYDINLATMA METNI</h2><p>Veri Sorumlusu: otelturizm.com İşletmecisi (&quot;Şirket&quot;) Kapsam: İşbu metin, Platformu kullanan Müşterileri, Ziyaretçileri ve Partner Firma (Otel) çalışanları ile yetkililerini kapsamaktadır. 6698 sayılı Kişisel Verilerin Korunması Kanunu (&quot;KVKK&quot;) uyarınca, Şirketimiz tarafından Veri Sorumlusu sıfatıyla, kişisel verileriniz aşağıda açıklanan amaçlar kapsamında; hukuka, dürüstlük kurallarına uygun olarak ve yasal saklama süreleri boyunca işlenebilecek, kaydedilebilecek ve aktarılabilecektir.</p><h2>1. İŞLENEN KİŞİSEL VERİ KATEGORİLERİ VE İŞLENME AMAÇLARI</h2><p>A. Müşteriler İçin: Kimlik ve İletişim Verileri (Ad, Soyad, TC No, Pasaport, Telefon, E-posta): Rezervasyonun oluşturulması, teyidi,  fatura  kesimi,  konaklama  kaydının  yapılması  ve  olası  değişiklik/iptal  durumlarında  iletişim  kurulması amacıyla işlenir. (Hukuki Sebep: Sözleşmenin ifası ve yasal yükümlülük). Finansal Veriler (Maskelenmiş Kart Bilgisi, Ödeme Tutarı): Ödeme işleminin güvenli bir şekilde alınması ve muhasebe kayıtlarının tutulması amacıyla işlenir. İşlem Güvenliği Verileri (IP Adresi, Log Kayıtları): 5651 sayılı Kanun gereği sistem güvenliğinin sağlanması amacıyla işlenir. B. Partner Firmalar (Oteller) İçin: Otel yetkililerine ait kimlik, iletişim ve imza verileri; ticari sözleşmenin kurulması, komisyon ödemelerinin ve mutabakatların yapılması, yasal fatura süreçlerinin yönetilmesi amacıyla işlenmektedir.</p><h2>2. KİŞİSEL VERİLERİN AKTARIMI</h2><p>Toplanan  kişisel  verileriniz;  işlenme  amaçlarının  yerine  getirilmesiyle  sınırlı  olarak  aşağıdaki  alıcılara aktarılmaktadır: Partner Oteller: Rezervasyon yapan Müşteriye ait ad, soyad ve iletişim bilgileri, hizmetin sunulabilmesi ve Kimlik Bildirme Kanunu gereği yasal giriş işlemlerinin yapılması için  sadece rezervasyon yapılan Otel ile paylaşılır. Ödeme ve Altyapı Kuruluşları: Ödemelerin tahsili ve komisyon transferleri için BDDK/TCMB lisanslı yetkili ödeme kuruluşlarına (Sanal POS hizmet sağlayıcıları) aktarılır. Yetkili Kamu Kurumları: Emniyet Genel Müdürlüğü (KBS sistemi), maliye ve adli mercilerden gelen yasal talepler doğrultusunda yetkili makamlarla paylaşılır.</p><h2>3. İLGİLİ KİŞİNİN HAKLARI VE BAŞVURU (KVKK MADDE 11)</h2><p>KVKK&#x27;nın 11. maddesi kapsamında, kişisel verilerinizin işlenip işlenmediğini öğrenme, işlenme amacına uygun kullanılıp kullanılmadığını bilme, yurt içinde/yurt dışında aktarıldığı 3. kişileri bilme, eksik veya yanlış işlenmişse düzeltilmesini  isteme,  kanunda  öngörülen  şartlar  çerçevesinde  silinmesini/yok  edilmesini  isteme  haklarına sahipsiniz. Bu  haklarınıza  ilişkin  taleplerinizi  &quot;Veri  Sorumlusuna  Başvuru  Usul  ve  Esasları  Hakkında  Tebliğ&quot;  uyarınca kvkk@otelturizm.com adresine  e-posta  göndererek  veya  kayıtlı  şirket  adresimize  ıslak  imzalı  dilekçe  ile iletebilirsiniz.</p>';
DECLARE @kullanici_kvkk_aydinlatma_ozet nvarchar(max) = N'<p>Veri Sorumlusu: otelturizm.com İşletmecisi (&amp;quot;Şirket&amp;quot;) Kapsam: İşbu metin, Platformu kullanan Müşterileri, Ziyaretçileri ve Partner Firma (Otel) çalışanları ile yetkililerini kapsamaktadır. 6698 sayılı Kişisel Verilerin Korunması Kanunu (&amp;quot;KVKK&amp;quot;) uyarınca, Şirke…</p>';
UPDATE [dbo].[SOZLESMELER] SET [ICERIK_HTML]=@kullanici_kvkk_aydinlatma_html, [OZET_HTML]=@kullanici_kvkk_aydinlatma_ozet, [VERSIYON_NO]=CASE WHEN [VERSIYON_NO]<2 THEN 2 ELSE [VERSIYON_NO] END, [GUNCELLENME_TARIHI]=SYSUTCDATETIME() WHERE [SLUG]=N'kullanici-kvkk-aydinlatma' AND [AKTIF_MI]=1;

DECLARE @partner_basvuru_sozlesmesi_html nvarchar(max) = N'<h2>OTELTURİZM.COM</h2><h2>PARTNER FIRMA (TESIS) TICARI İŞBIRLIĞI SÖZLEŞMESI</h2><p>Doküman Ref: OT-PRT-26/V2 | Geçerlilik Tarihi: 06 Haziran 2026 İşbu  Sözleşme,  merkezi  [Şirket  Adresi]  adresinde  bulunan  ve  otelturizm.com alan  adını  işleten  Platform  ile, Platform üzerinden konaklama hizmetlerini satışa sunan, aşağıda/sistemde bilgileri yer alan Partner Firma (Otel/ Tesis) arasında akdedilmiştir.</p><h2>1. SÖZLEŞMENİN AMACI VE TARAFLARIN ROLLERİ</h2><p>Platform,  Partner  Firma&#x27;nın  oda  ve  hizmetlerini  dijital  ortamda  son  kullanıcılara  (Müşteri)  sunmasını  sağlayan teknolojik bir aracıdır. Partner Firma ise, 6502 sayılı Tüketicinin Korunması Hakkında Kanun uyarınca &quot;Sağlayıcı&quot; sıfatını haiz olup, konaklama hizmetinin eksiksiz ve taahhüt edilen kalitede ifasından doğrudan sorumludur.</p><h2>2. MALİ HÜKÜMLER, KOMİSYON VE HAK EDİŞ ÖDEMELERİ</h2><p>Platform üzerinden gerçekleştirilen online ön ödemeli rezervasyonlara ilişkin tahsilatlar Platform&#x27;un güvenli havuz hesabında toplanır. Ödeme takvimi ve komisyon kesintileri aşağıdaki kesin kurallara tabidir: ÖNEMLİ: Her Ayın 15&#x27;i Ödeme Kuralı Müşterinin &quot;N&quot; ayı içerisinde (örneğin Mayıs ayı) check-out yaptığı rezervasyonlara ait toplam bedel üzerinden, Sözleşme&#x27;de belirlenen Platform Hizmet Komisyonu mahsup edilir. Kalan Net Hak Ediş tutarı, takip eden ayın ilk 5 gününde yapılan mutabakatın ardından, her ayın 15&#x27;inci günü Partner Firma&#x27;nın sisteme tanımlı resmi banka hesabına EFT/Havale yoluyla defaten ödenir. Ayın 15&#x27;inin resmi tatil veya hafta sonuna denk gelmesi halinde ödeme, takip eden ilk iş günü gerçekleştirilir.</p><h2>3. OVERBOOKING (ÇİFTE REZERVASYON) VE CEZAİ ŞARTLAR</h2><p>Partner Firma, sistem üzerindeki kontenjan ve fiyatlarını anlık olarak güncel tutmakla yükümlüdür. Partner Firma&#x27;nın kusuru,  personel  hatası  veya  kanal  yöneticisi  (channel  manager)  entegrasyon  arızası  sebebiyle  oluşan Overbooking (Kapasite Aşımı) durumlarında: Partner Firma, Müşteri&#x27;ye aynı bölgede, aynı veya daha üst standartta (yıldız, konsept, oda tipi) alternatif bir tesis bulmakla yükümlüdür. Alternatif tesisin ücret farkı, transfer bedeli ve Müşteri&#x27;nin doğabilecek tüm maddi/manevi zararları şartsız olarak Partner Firma tarafından karşılanır. Bu yükümlülüğün yerine getirilmemesi halinde Platform, mağduriyeti giderir ve doğan tüm masrafları Partner Firma&#x27;nın ayın 15&#x27;indeki hak edişinden re&#x27;sen kesme (mahsup etme) hakkına sahiptir.</p><h2>4. HİZMET KALİTESİ VE FİYAT EŞİTLİĞİ (RATE PARITY)</h2><p>Partner Firma, otelturizm.com üzerinden gelen Müşterilere, kendi doğrudan satış kanallarından (kendi web sitesi, telefon, çağrı merkezi) gelen müşterilere uyguladığı fiyatlardan daha yüksek bir fiyat uygulayamaz. Ayrıca, otele giriş  anında  &quot;Platform  müşterilerine  farklı  standart,  doğrudan  müşterilere  ayrıcalıklı  standart&quot;  şeklinde  ayrımcı uygulamalar yapılması kesinlikle yasaktır. otelturizm.com Platformu Yetkili İmza Ad-Soyad / Kaşe / Tarih Partner Firma (Tesis) Yetkili İmza Ad-Soyad / Kaşe / Tarih</p>';
DECLARE @partner_basvuru_sozlesmesi_ozet nvarchar(max) = N'<p>Doküman Ref: OT-PRT-26/V2 | Geçerlilik Tarihi: 06 Haziran 2026 İşbu  Sözleşme,  merkezi  [Şirket  Adresi]  adresinde  bulunan  ve  otelturizm.com alan  adını  işleten  Platform  ile, Platform üzerinden konaklama hizmetlerini satışa sunan, aşağıda/sistemde bilgileri yer alan Partn…</p>';
UPDATE [dbo].[SOZLESMELER] SET [ICERIK_HTML]=@partner_basvuru_sozlesmesi_html, [OZET_HTML]=@partner_basvuru_sozlesmesi_ozet, [VERSIYON_NO]=CASE WHEN [VERSIYON_NO]<2 THEN 2 ELSE [VERSIYON_NO] END, [GUNCELLENME_TARIHI]=SYSUTCDATETIME() WHERE [SLUG]=N'partner-basvuru-sozlesmesi' AND [AKTIF_MI]=1;

DECLARE @partner_kvkk_aydinlatma_html nvarchar(max) = N'<p>OTELTURİZM Partner KVKK Aydınlatma Metni Versiyon: 2 Yürürlük tarihi: 01 Haziran 2026 Kapsam: Partner başvuru, tesis yönetimi ve operasyon verilerinin işlenmesine ilişkin bilgilendirme.</p><h2>1. Veri Sorumlusu ve Kapsam</h2><p>Bu aydınlatma metni, partner başvurusu ve tesis yönetimi süreçlerinde işlenen kişisel veriler hakkında 6698 sayılı Kişisel Verilerin Korunması Kanunu kapsamında bilgilendirme amacıyla hazırlanmıştır.</p><h2>2. İşlenen Veri Kategorileri</h2><p>Yetkili ad soyad, iletişim bilgileri, görev/unvan, kimlik doğrulama bilgileri, vergi ve ticaret kayıtları, tesis evrakları, banka/IBAN bilgileri, panel işlem kayıtları, IP ve cihaz kayıtları, destek yazışmaları, rezervasyon ve fatura süreçlerine ilişkin veriler işlenebilir.</p><h2>3. İşleme Amaçları</h2><p>Başvurunun alınması, yetki ve belge doğrulaması, tesis yayın kararı, rezervasyon operasyonu, komisyon/mutabakat, fatura yönetimi, güvenlik, dolandırıcılık önleme, destek, mevzuat yükümlülükleri ve platform kalite denetimi amaçlarıyla veri işlenir.</p><h2>4. Aktarım</h2><p>Veriler; mevzuatın izin verdiği ölçüde yetkili kamu kurumları, ödeme ve e-posta hizmet sağlayıcıları, barındırma/altyapı hizmetleri, hukuk/muhasebe danışmanları ve rezervasyon sürecinin gerektirdiği taraflarla paylaşılabilir.</p><h2>5. Saklama ve Güvenlik</h2><p>Veriler, işleme amacı ve yasal saklama süreleriyle sınırlı olarak tutulur. Evrak ve dosyalar güvenli dosya alanında, erişim tokenları ve yetki kontrolleriyle korunur.</p><h2>6. İlgili Kişi Hakları</h2><p>KVKK madde 11 kapsamındaki başvurularınızı Otelturizm destek kanalları veya kayıtlı iletişim adresleri üzerinden iletebilirsiniz. Bu metin partner başvurusu sırasında elektronik olarak sunulur ve partner hesabına PDF olarak gönderilebilir.   1/1</p>';
DECLARE @partner_kvkk_aydinlatma_ozet nvarchar(max) = N'<p>OTELTURİZM Partner KVKK Aydınlatma Metni Versiyon: 2 Yürürlük tarihi: 01 Haziran 2026 Kapsam: Partner başvuru, tesis yönetimi ve operasyon verilerinin işlenmesine ilişkin bilgilendirme.</p>';
UPDATE [dbo].[SOZLESMELER] SET [ICERIK_HTML]=@partner_kvkk_aydinlatma_html, [OZET_HTML]=@partner_kvkk_aydinlatma_ozet, [VERSIYON_NO]=CASE WHEN [VERSIYON_NO]<2 THEN 2 ELSE [VERSIYON_NO] END, [GUNCELLENME_TARIHI]=SYSUTCDATETIME() WHERE [SLUG]=N'partner-kvkk-aydinlatma' AND [AKTIF_MI]=1;

DECLARE @firma_kurumsal_kullanim_kosullari_html nvarchar(max) = N'<h2>OTELTURİZM.COM KURUMSAL FİRMA KULLANIM SÖZLEŞMESİ</h2>
<p>Doküman Ref: OT-FRM-26/V2 | Geçerlilik Tarihi: 06 Haziran 2026</p>
<p>İşbu Sözleşme; otelturizm.com platformunu kurumsal firma hesabı ile kullanan, çalışan veya yetkili adına konaklama rezervasyonu yapan tüzel kişiler (Firma) ile Platform arasındaki hak ve yükümlülükleri düzenler.</p>
<h2>1. Taraflar ve kapsam</h2>
<p>Platform, kurumsal firma hesabı üzerinden otel arama, rezervasyon, onay akışı, faturalama ve raporlama hizmetlerini sunar. Konaklama hizmetinin ifası ilgili tesis (Partner) sorumluluğundadır.</p>
<h2>2. Hesap, yetki ve başvuru</h2>
<p>Firma; başvuru formunda verdiği unvan, vergi, yetkili ve evrak bilgilerinin doğruluğundan sorumludur. Admin onayı tamamlanmadan tam panel kullanımı ve kurumsal rezervasyon yetkisi açılmaz.</p>
<h2>3. Rezervasyon ve çalışan verileri</h2>
<p>Firma, çalışan veya misafir adına rezervasyon oluştururken doğru kimlik ve iletişim bilgisi girmekle yükümlüdür. Kişisel veriler yalnızca hizmet ifası için işlenir; KVKK aydınlatma metni geçerlidir.</p>
<h2>4. Faturalama ve ödeme</h2>
<p>Kurumsal faturalar, panelde tanımlı fatura adresi ve vergi bilgilerine göre düzenlenir. Ödeme koşulları, kampanya ve otel politikaları rezervasyon özetinde gösterilir.</p>
<h2>5. İptal, değişiklik ve no-show</h2>
<p>İptal ve iade koşulları ilgili otel politikası ve 6502 sayılı Tüketicinin Korunması Hakkında Kanun hükümlerine tabidir. Firma, çalışanları bu koşullar hakkında bilgilendirmekle yükümlüdür.</p>
<h2>6. Gizlilik ve güvenlik</h2>
<p>Firma panel erişim bilgilerinin gizliliğinden sorumludur. Yetkisiz kullanım şüphesinde Platform destek kanallarına derhal bildirim yapılır.</p>
<h2>7. Uyuşmazlık</h2>
<p>İşbu sözleşmeden doğan uyuşmazlıklarda İstanbul mahkemeleri ve icra daireleri yetkilidir. Zorunlu tüketici hükümleri saklıdır.</p>
<h2>8. Yürürlük</h2>
<p>Sözleşme, başvuru formundaki elektronik onay ile kabul edilmiş sayılır. Güncel sürüm platform üzerinden yayımlanır.</p>';
DECLARE @firma_kurumsal_kullanim_kosullari_ozet nvarchar(max) = N'<p>Doküman Ref: OT-FRM-26/V2 | Geçerlilik Tarihi: 06 Haziran 2026</p>';
UPDATE [dbo].[SOZLESMELER] SET [ICERIK_HTML]=@firma_kurumsal_kullanim_kosullari_html, [OZET_HTML]=@firma_kurumsal_kullanim_kosullari_ozet, [VERSIYON_NO]=CASE WHEN [VERSIYON_NO]<2 THEN 2 ELSE [VERSIYON_NO] END, [GUNCELLENME_TARIHI]=SYSUTCDATETIME() WHERE [SLUG]=N'firma-kurumsal-kullanim-kosullari' AND [AKTIF_MI]=1;

DECLARE @firma_kvkk_aydinlatma_html nvarchar(max) = N'<h2>OTELTURİZM.COM</h2><h2>KIŞISEL VERILERIN KORUNMASI (KVKK) AYDINLATMA METNI</h2><p>Veri Sorumlusu: otelturizm.com İşletmecisi (&quot;Şirket&quot;) Kapsam: İşbu metin, Platformu kullanan Müşterileri, Ziyaretçileri ve Partner Firma (Otel) çalışanları ile yetkililerini kapsamaktadır. 6698 sayılı Kişisel Verilerin Korunması Kanunu (&quot;KVKK&quot;) uyarınca, Şirketimiz tarafından Veri Sorumlusu sıfatıyla, kişisel verileriniz aşağıda açıklanan amaçlar kapsamında; hukuka, dürüstlük kurallarına uygun olarak ve yasal saklama süreleri boyunca işlenebilecek, kaydedilebilecek ve aktarılabilecektir.</p><h2>1. İŞLENEN KİŞİSEL VERİ KATEGORİLERİ VE İŞLENME AMAÇLARI</h2><p>A. Müşteriler İçin: Kimlik ve İletişim Verileri (Ad, Soyad, TC No, Pasaport, Telefon, E-posta): Rezervasyonun oluşturulması, teyidi,  fatura  kesimi,  konaklama  kaydının  yapılması  ve  olası  değişiklik/iptal  durumlarında  iletişim  kurulması amacıyla işlenir. (Hukuki Sebep: Sözleşmenin ifası ve yasal yükümlülük). Finansal Veriler (Maskelenmiş Kart Bilgisi, Ödeme Tutarı): Ödeme işleminin güvenli bir şekilde alınması ve muhasebe kayıtlarının tutulması amacıyla işlenir. İşlem Güvenliği Verileri (IP Adresi, Log Kayıtları): 5651 sayılı Kanun gereği sistem güvenliğinin sağlanması amacıyla işlenir. B. Partner Firmalar (Oteller) İçin: Otel yetkililerine ait kimlik, iletişim ve imza verileri; ticari sözleşmenin kurulması, komisyon ödemelerinin ve mutabakatların yapılması, yasal fatura süreçlerinin yönetilmesi amacıyla işlenmektedir.</p><h2>2. KİŞİSEL VERİLERİN AKTARIMI</h2><p>Toplanan  kişisel  verileriniz;  işlenme  amaçlarının  yerine  getirilmesiyle  sınırlı  olarak  aşağıdaki  alıcılara aktarılmaktadır: Partner Oteller: Rezervasyon yapan Müşteriye ait ad, soyad ve iletişim bilgileri, hizmetin sunulabilmesi ve Kimlik Bildirme Kanunu gereği yasal giriş işlemlerinin yapılması için  sadece rezervasyon yapılan Otel ile paylaşılır. Ödeme ve Altyapı Kuruluşları: Ödemelerin tahsili ve komisyon transferleri için BDDK/TCMB lisanslı yetkili ödeme kuruluşlarına (Sanal POS hizmet sağlayıcıları) aktarılır. Yetkili Kamu Kurumları: Emniyet Genel Müdürlüğü (KBS sistemi), maliye ve adli mercilerden gelen yasal talepler doğrultusunda yetkili makamlarla paylaşılır.</p><h2>3. İLGİLİ KİŞİNİN HAKLARI VE BAŞVURU (KVKK MADDE 11)</h2><p>KVKK&#x27;nın 11. maddesi kapsamında, kişisel verilerinizin işlenip işlenmediğini öğrenme, işlenme amacına uygun kullanılıp kullanılmadığını bilme, yurt içinde/yurt dışında aktarıldığı 3. kişileri bilme, eksik veya yanlış işlenmişse düzeltilmesini  isteme,  kanunda  öngörülen  şartlar  çerçevesinde  silinmesini/yok  edilmesini  isteme  haklarına sahipsiniz. Bu  haklarınıza  ilişkin  taleplerinizi  &quot;Veri  Sorumlusuna  Başvuru  Usul  ve  Esasları  Hakkında  Tebliğ&quot;  uyarınca kvkk@otelturizm.com adresine  e-posta  göndererek  veya  kayıtlı  şirket  adresimize  ıslak  imzalı  dilekçe  ile iletebilirsiniz.</p>';
DECLARE @firma_kvkk_aydinlatma_ozet nvarchar(max) = N'<p>Veri Sorumlusu: otelturizm.com İşletmecisi (&amp;quot;Şirket&amp;quot;) Kapsam: İşbu metin, Platformu kullanan Müşterileri, Ziyaretçileri ve Partner Firma (Otel) çalışanları ile yetkililerini kapsamaktadır. 6698 sayılı Kişisel Verilerin Korunması Kanunu (&amp;quot;KVKK&amp;quot;) uyarınca, Şirke…</p>';
UPDATE [dbo].[SOZLESMELER] SET [ICERIK_HTML]=@firma_kvkk_aydinlatma_html, [OZET_HTML]=@firma_kvkk_aydinlatma_ozet, [VERSIYON_NO]=CASE WHEN [VERSIYON_NO]<2 THEN 2 ELSE [VERSIYON_NO] END, [GUNCELLENME_TARIHI]=SYSUTCDATETIME() WHERE [SLUG]=N'firma-kvkk-aydinlatma' AND [AKTIF_MI]=1;

IF OBJECT_ID(N'dbo.SOZLESME_DOSYALARI', N'U') IS NOT NULL
BEGIN
    IF NOT EXISTS (SELECT 1 FROM [dbo].[SOZLESME_DOSYALARI] d INNER JOIN [dbo].[SOZLESMELER] s ON s.[ID]=d.[SOZLESME_ID] WHERE s.[SLUG]=N'kullanici-kullanim-kosullari' AND d.[DOSYA_TIPI]=N'pdf' AND d.[DOSYA_YOLU]=N'/uploads/contracts/kullanici-kullanim-kosullari-v2.pdf')
    BEGIN
        INSERT INTO [dbo].[SOZLESME_DOSYALARI] ([SOZLESME_ID],[DOSYA_TIPI],[DOSYA_ADI],[DOSYA_YOLU],[MIME_TIPI],[OLUSTURULMA_TARIHI]) SELECT TOP (1) s.[ID], N'pdf', N'Kullanici Kullanim Sozlesmesi v2.pdf', N'/uploads/contracts/kullanici-kullanim-kosullari-v2.pdf', N'application/pdf', SYSUTCDATETIME() FROM [dbo].[SOZLESMELER] s WHERE s.[SLUG]=N'kullanici-kullanim-kosullari' AND s.[AKTIF_MI]=1 ORDER BY s.[VERSIYON_NO] DESC, s.[ID] DESC;
    END;
    IF NOT EXISTS (SELECT 1 FROM [dbo].[SOZLESME_DOSYALARI] d INNER JOIN [dbo].[SOZLESMELER] s ON s.[ID]=d.[SOZLESME_ID] WHERE s.[SLUG]=N'kullanici-kvkk-aydinlatma' AND d.[DOSYA_TIPI]=N'pdf' AND d.[DOSYA_YOLU]=N'/uploads/contracts/kullanici-kvkk-aydinlatma-v2.pdf')
    BEGIN
        INSERT INTO [dbo].[SOZLESME_DOSYALARI] ([SOZLESME_ID],[DOSYA_TIPI],[DOSYA_ADI],[DOSYA_YOLU],[MIME_TIPI],[OLUSTURULMA_TARIHI]) SELECT TOP (1) s.[ID], N'pdf', N'KVKK Aydinlatma Metni v2.pdf', N'/uploads/contracts/kullanici-kvkk-aydinlatma-v2.pdf', N'application/pdf', SYSUTCDATETIME() FROM [dbo].[SOZLESMELER] s WHERE s.[SLUG]=N'kullanici-kvkk-aydinlatma' AND s.[AKTIF_MI]=1 ORDER BY s.[VERSIYON_NO] DESC, s.[ID] DESC;
    END;
    IF NOT EXISTS (SELECT 1 FROM [dbo].[SOZLESME_DOSYALARI] d INNER JOIN [dbo].[SOZLESMELER] s ON s.[ID]=d.[SOZLESME_ID] WHERE s.[SLUG]=N'partner-basvuru-sozlesmesi' AND d.[DOSYA_TIPI]=N'pdf' AND d.[DOSYA_YOLU]=N'/uploads/contracts/partner-basvuru-sozlesmesi-v2.pdf')
    BEGIN
        INSERT INTO [dbo].[SOZLESME_DOSYALARI] ([SOZLESME_ID],[DOSYA_TIPI],[DOSYA_ADI],[DOSYA_YOLU],[MIME_TIPI],[OLUSTURULMA_TARIHI]) SELECT TOP (1) s.[ID], N'pdf', N'Partner Kullanim Sozlesmesi v2.pdf', N'/uploads/contracts/partner-basvuru-sozlesmesi-v2.pdf', N'application/pdf', SYSUTCDATETIME() FROM [dbo].[SOZLESMELER] s WHERE s.[SLUG]=N'partner-basvuru-sozlesmesi' AND s.[AKTIF_MI]=1 ORDER BY s.[VERSIYON_NO] DESC, s.[ID] DESC;
    END;
    IF NOT EXISTS (SELECT 1 FROM [dbo].[SOZLESME_DOSYALARI] d INNER JOIN [dbo].[SOZLESMELER] s ON s.[ID]=d.[SOZLESME_ID] WHERE s.[SLUG]=N'partner-kvkk-aydinlatma' AND d.[DOSYA_TIPI]=N'pdf' AND d.[DOSYA_YOLU]=N'/uploads/contracts/partner-kvkk-aydinlatma-v2.pdf')
    BEGIN
        INSERT INTO [dbo].[SOZLESME_DOSYALARI] ([SOZLESME_ID],[DOSYA_TIPI],[DOSYA_ADI],[DOSYA_YOLU],[MIME_TIPI],[OLUSTURULMA_TARIHI]) SELECT TOP (1) s.[ID], N'pdf', N'Partner KVKK Aydinlatma Metni v2.pdf', N'/uploads/contracts/partner-kvkk-aydinlatma-v2.pdf', N'application/pdf', SYSUTCDATETIME() FROM [dbo].[SOZLESMELER] s WHERE s.[SLUG]=N'partner-kvkk-aydinlatma' AND s.[AKTIF_MI]=1 ORDER BY s.[VERSIYON_NO] DESC, s.[ID] DESC;
    END;
    IF NOT EXISTS (SELECT 1 FROM [dbo].[SOZLESME_DOSYALARI] d INNER JOIN [dbo].[SOZLESMELER] s ON s.[ID]=d.[SOZLESME_ID] WHERE s.[SLUG]=N'firma-kurumsal-kullanim-kosullari' AND d.[DOSYA_TIPI]=N'pdf' AND d.[DOSYA_YOLU]=N'/uploads/contracts/firma-kurumsal-kullanim-kosullari-v2.pdf')
    BEGIN
        INSERT INTO [dbo].[SOZLESME_DOSYALARI] ([SOZLESME_ID],[DOSYA_TIPI],[DOSYA_ADI],[DOSYA_YOLU],[MIME_TIPI],[OLUSTURULMA_TARIHI]) SELECT TOP (1) s.[ID], N'pdf', N'Firma Kurumsal Kullanim Sozlesmesi v2.pdf', N'/uploads/contracts/firma-kurumsal-kullanim-kosullari-v2.pdf', N'application/pdf', SYSUTCDATETIME() FROM [dbo].[SOZLESMELER] s WHERE s.[SLUG]=N'firma-kurumsal-kullanim-kosullari' AND s.[AKTIF_MI]=1 ORDER BY s.[VERSIYON_NO] DESC, s.[ID] DESC;
    END;
    IF NOT EXISTS (SELECT 1 FROM [dbo].[SOZLESME_DOSYALARI] d INNER JOIN [dbo].[SOZLESMELER] s ON s.[ID]=d.[SOZLESME_ID] WHERE s.[SLUG]=N'firma-kvkk-aydinlatma' AND d.[DOSYA_TIPI]=N'pdf' AND d.[DOSYA_YOLU]=N'/uploads/contracts/firma-kvkk-aydinlatma-v2.pdf')
    BEGIN
        INSERT INTO [dbo].[SOZLESME_DOSYALARI] ([SOZLESME_ID],[DOSYA_TIPI],[DOSYA_ADI],[DOSYA_YOLU],[MIME_TIPI],[OLUSTURULMA_TARIHI]) SELECT TOP (1) s.[ID], N'pdf', N'Firma KVKK Aydinlatma Metni v2.pdf', N'/uploads/contracts/firma-kvkk-aydinlatma-v2.pdf', N'application/pdf', SYSUTCDATETIME() FROM [dbo].[SOZLESMELER] s WHERE s.[SLUG]=N'firma-kvkk-aydinlatma' AND s.[AKTIF_MI]=1 ORDER BY s.[VERSIYON_NO] DESC, s.[ID] DESC;
    END;
END;

SELECT s.[SLUG], s.[VERSIYON_NO], LEN(s.[ICERIK_HTML]) AS html_len, d.[DOSYA_YOLU] FROM [dbo].[SOZLESMELER] s LEFT JOIN [dbo].[SOZLESME_DOSYALARI] d ON d.[SOZLESME_ID]=s.[ID] AND d.[DOSYA_TIPI]=N'pdf' WHERE s.[SLUG] IN (N'partner-basvuru-sozlesmesi',N'partner-kvkk-aydinlatma',N'firma-kurumsal-kullanim-kosullari',N'firma-kvkk-aydinlatma',N'kullanici-kullanim-kosullari',N'kullanici-kvkk-aydinlatma') ORDER BY s.[SLUG], d.[ID] DESC;